#!/usr/bin/env bash
set -euo pipefail

SCRIPT_NAME="Aster Browser Ultimate Installer"
SCRIPT_VERSION="2026.04.18-r2"
DEFAULT_PREFIX="${HOME}/.local/share/aster-browser-ultimate"
DEFAULT_BIN_DIR="${HOME}/.local/bin"
DEFAULT_LAUNCHER_NAME="aster-browser-ultimate"
NO_RUN=0
SKIP_DESKTOP=0
EXTRACT_ONLY=""
PREFIX="${DEFAULT_PREFIX}"
BIN_DIR="${DEFAULT_BIN_DIR}"

usage() {
  cat <<'EOU'
Aster Browser Ultimate installer

Usage:
  ./Aster-Browser-Ultimate-TTS-TransparencyFix.sh [options]

Options:
  --prefix DIR         Install into DIR (default: ~/.local/share/aster-browser-ultimate)
  --bin-dir DIR        Put the launcher in DIR (default: ~/.local/bin)
  --extract-only DIR   Only extract the bundled source tree into DIR
  --export-source DIR  Same as --extract-only
  --no-run             Install but do not launch
  --skip-desktop       Do not create a desktop entry
  --help               Show this help

What this installer includes:
  - transparency hotfix with a painted outer window surface for frameless mode
  - 3x2 browser menu dashboard with History, Bookmarks, Settings, Downloads,
    Awareness, Extensions, plus an Aster AI button and live resource stats
  - wider wrapped settings page with the horizontal-scroll issue fixed
  - image, media, and linked-file download actions from the page context menu
    with direct-download fallback
  - read-aloud tools with Qt speech, Piper voice installs/removals, and
    reference-audio import/record hooks for custom local voice cloning
  - portable user-space install suitable for Linux desktops and Steam Deck
EOU
}

info() {
  printf '[%s] %s\n' "${SCRIPT_NAME}" "$*"
}

fail() {
  printf '[%s] ERROR: %s\n' "${SCRIPT_NAME}" "$*" >&2
  exit 1
}

extract_payload() {
  local dest="$1"
  mkdir -p "$dest"
  local payload_line
  payload_line="$(awk '/^__ASTER_PAYLOAD_BELOW__$/ { print NR + 1; exit }' "$0")"
  [ -n "$payload_line" ] || fail "Could not find the embedded payload."
  tail -n +"$payload_line" "$0" | base64 --decode | tar -xzf - -C "$dest"
}

create_launcher() {
  local launcher_path="$1"
  local app_root="$2"
  local src_dir="$3"
  local venv_dir="$4"
  local portable_root="$5"
  mkdir -p "$(dirname "$launcher_path")"
  cat >"$launcher_path" <<EOF2
#!/usr/bin/env bash
set -euo pipefail
APP_ROOT="$(printf '%q' "$app_root")"
SRC_DIR="$(printf '%q' "$src_dir")"
VENV_DIR="$(printf '%q' "$venv_dir")"
PORTABLE_ROOT="$(printf '%q' "$portable_root")"
export ASTER_PORTABLE=1
export ASTER_PORTABLE_ROOT="\${PORTABLE_ROOT}"
export QTWEBENGINE_CHROMIUM_FLAGS="\${QTWEBENGINE_CHROMIUM_FLAGS:-} --ozone-platform-hint=auto"
cd "\${SRC_DIR}"
exec "\${VENV_DIR}/bin/python" "\${SRC_DIR}/run_aster.py" "\$@"
EOF2
  chmod +x "$launcher_path"
}

create_desktop_file() {
  local desktop_path="$1"
  local launcher_path="$2"
  local icon_path="$3"
  mkdir -p "$(dirname "$desktop_path")"
  cat >"$desktop_path" <<EOF2
[Desktop Entry]
Type=Application
Name=Aster Browser Ultimate
Comment=Linux-first browser with dashboard menu, transparency fixes, read-aloud, and downloads
Exec=${launcher_path}
Icon=${icon_path}
Categories=Network;WebBrowser;Utility;
Terminal=false
StartupNotify=true
EOF2
}

while (($#)); do
  case "$1" in
    --prefix)
      shift
      [ $# -gt 0 ] || fail "Missing value for --prefix"
      PREFIX="$1"
      ;;
    --bin-dir)
      shift
      [ $# -gt 0 ] || fail "Missing value for --bin-dir"
      BIN_DIR="$1"
      ;;
    --extract-only|--export-source)
      shift
      [ $# -gt 0 ] || fail "Missing directory for extract"
      EXTRACT_ONLY="$1"
      ;;
    --no-run)
      NO_RUN=1
      ;;
    --skip-desktop)
      SKIP_DESKTOP=1
      ;;
    --help|-h)
      usage
      exit 0
      ;;
    *)
      fail "Unknown option: $1"
      ;;
  esac
  shift || true
done

if [ -n "${EXTRACT_ONLY}" ]; then
  info "Extracting bundled source to ${EXTRACT_ONLY}"
  extract_payload "${EXTRACT_ONLY}"
  info "Done."
  exit 0
fi

command -v python3 >/dev/null 2>&1 || fail "python3 is required."
python3 - <<'PY' >/dev/null 2>&1 || fail "The python3 venv module is required."
import venv
PY

PREFIX="$(python3 -c 'import os,sys; print(os.path.abspath(os.path.expanduser(sys.argv[1])))' "$PREFIX")"
BIN_DIR="$(python3 -c 'import os,sys; print(os.path.abspath(os.path.expanduser(sys.argv[1])))' "$BIN_DIR")"
APP_ROOT="${PREFIX}/app"
SRC_DIR="${APP_ROOT}/src"
VENV_DIR="${APP_ROOT}/venv"
PORTABLE_ROOT="${PREFIX}/portable-data"
LAUNCHER_PATH="${BIN_DIR}/${DEFAULT_LAUNCHER_NAME}"
DESKTOP_PATH="${HOME}/.local/share/applications/${DEFAULT_LAUNCHER_NAME}.desktop"
ICON_DIR="${PREFIX}/icons"
ICON_PATH="${ICON_DIR}/aster.svg"

STAGING_DIR="$(mktemp -d)"
cleanup() {
  rm -rf "${STAGING_DIR}"
}
trap cleanup EXIT

info "Extracting bundled source tree"
extract_payload "${STAGING_DIR}"

info "Preparing folders"
mkdir -p "${APP_ROOT}" "${BIN_DIR}" "${PORTABLE_ROOT}" "${ICON_DIR}"
rm -rf "${SRC_DIR}" "${VENV_DIR}"
mkdir -p "${SRC_DIR}"
cp -a "${STAGING_DIR}/." "${SRC_DIR}/"

info "Creating virtual environment"
python3 -m venv "${VENV_DIR}"

info "Upgrading pip tooling"
"${VENV_DIR}/bin/python" -m pip install --upgrade pip setuptools wheel

info "Installing Python dependencies"
"${VENV_DIR}/bin/python" -m pip install --no-cache-dir -r "${SRC_DIR}/requirements.txt"

info "Creating launcher"
create_launcher "${LAUNCHER_PATH}" "${APP_ROOT}" "${SRC_DIR}" "${VENV_DIR}" "${PORTABLE_ROOT}"

if [ -f "${SRC_DIR}/packaging/linux/aster.svg" ]; then
  cp -f "${SRC_DIR}/packaging/linux/aster.svg" "${ICON_PATH}"
fi

if [ "${SKIP_DESKTOP}" -eq 0 ]; then
  info "Creating desktop entry"
  create_desktop_file "${DESKTOP_PATH}" "${LAUNCHER_PATH}" "${ICON_PATH}"
fi

cat <<EOF2
Aster Browser Ultimate has been installed.

Launcher:
  ${LAUNCHER_PATH}

Source tree:
  ${SRC_DIR}

Portable user data:
  ${PORTABLE_ROOT}
EOF2

if [ "${NO_RUN}" -eq 0 ]; then
  info "Launching Aster Browser Ultimate"
  "${LAUNCHER_PATH}"
fi

exit 0
__ASTER_PAYLOAD_BELOW__

